## 2. `pcapng_stubs.cpp` – C/C++ glue

> **NOTE** – The file must be compiled as C++ (`g++`/`clang++`) and linked
> with the real *libpcapng* library.  The stub code below assumes the
> following simplified C++ API (you will have to adapt the `#include`
> and class names to the real library you are using).

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp  –  OCaml bindings for libpcapng
   --------------------------------------------------------------------*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <string>
#include <vector>
#include <memory>
#include <cstring>
#include <cstdio>

/* -----------------------------------------------------------------
   Minimal stub of the real libpcapng API (replace with the real one)
   ----------------------------------------------------------------- */

namespace pcapng {

struct Frame {
  double   ts;          // seconds since epoch
  uint32_t cap_len;     // captured length
  uint32_t orig_len;    // original length
  std::vector<unsigned char> data; // raw packet bytes

  Frame(double t, const std::vector<unsigned char>& d)
    : ts(t), cap_len(d.size()), orig_len(d.size()), data(d) {}
};

class Capture {
public:
  explicit Capture(const std::string& filename) {
    // In the real library you would parse the file.
    // Here we just fabricate two dummy frames.
    (void)filename; // suppress unused warning
    frames.emplace_back(1620000000.0,
        std::vector<unsigned char>{0x00,0x01,0x02,0x03,0x04,0x05, // dst MAC
                                    0x10,0x11,0x12,0x13,0x14,0x15}); // src MAC
    frames.emplace_back(1620000001.5,
        std::vector<unsigned char>{0xde,0xad,0xbe,0xef}); // short payload
  }
  ~Capture() = default;

  using iterator = std::vector<Frame>::iterator;
  iterator begin() { return frames.begin(); }
  iterator end()   { return frames.end(); }

private:
  std::vector<Frame> frames;
};

} // namespace pcapng

/* -----------------------------------------------------------------
   OCaml custom block definitions
   ----------------------------------------------------------------- */

static void finalize_capture(value v) {
  // The custom block holds a pointer to a std::unique_ptr<Capture>.
  std::unique_ptr<pcapng::Capture>* p = (std::unique_ptr<pcapng::Capture>*)Data_custom_val(v);
  delete p; // destroys the unique_ptr → frees the Capture
}

static struct custom_operations capture_ops = {
  "pcapng.capture",
  finalize_capture,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_fixed_length_default
};

static void finalize_frame(value v) {
  // The frame lives inside the parent Capture; we only free the wrapper.
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v);
  // No deletion – the frame is owned by the Capture's vector.
  // (We just set the pointer to nullptr for safety.)
  *(pcapng::Frame**)Data_custom_val(v) = nullptr;
}

static struct custom_operations frame_ops = {
  "pcapng.frame",
  finalize_frame,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_fixed_length_default
};

/* -----------------------------------------------------------------
   Helper: wrap a Capture* into an OCaml value
   ----------------------------------------------------------------- */
static value caml_wrap_capture(pcapng::Capture* cap) {
  CAMLparam0();
  // Allocate a custom block that holds a pointer to a std::unique_ptr<Capture>
  value v = caml_alloc_custom(&capture_ops, sizeof(std::unique_ptr<pcapng::Capture>), 0, 1);
  // Placement‑new a unique_ptr inside the block
  new (Data_custom_val(v)) std::unique_ptr<pcapng::Capture>(cap);
  CAMLreturn(v);
}

/* -----------------------------------------------------------------
   Helper: wrap a Frame* into an OCaml value (frame lives inside a
   Capture; we do NOT own it)
   ----------------------------------------------------------------- */
static value caml_wrap_frame(pcapng::Frame* f) {
  CAMLparam0();
  value v = caml_alloc_custom(&frame_ops, sizeof(pcapng::Frame*), 0, 1);
  *(pcapng::Frame**)Data_custom_val(v) = f;
  CAMLreturn(v);
}

/* -----------------------------------------------------------------
   OCaml primitives
   ----------------------------------------------------------------- */

extern "C" {

/* open_file : string -> capture */
CAMLprim value caml_pcapng_open_file(value v_path) {
  CAMLparam1(v_path);
  CAMLlocal1(v_res);
  const char* path = String_val(v_path);
  try {
    pcapng::Capture* cap = new pcapng::Capture(std::string(path));
    v_res = caml_wrap_capture(cap);
  } catch (const std::exception& ex) {
    caml_failwith(ex.what());
  }
  CAMLreturn(v_res);
}

/* close : capture -> unit */
CAMLprim value caml_pcapng_close(value v_cap) {
  CAMLparam1(v_cap);
  // The custom finalizer will free the object; we just clear the pointer.
  std::unique_ptr<pcapng::Capture>* p = (std::unique_ptr<pcapng::Capture>*)Data_custom_val(v_cap);
  p->reset(); // delete the underlying Capture
  CAMLreturn(Val_unit);
}

/* iter_frames : capture -> (frame -> unit) -> unit */
CAMLprim value caml_pcapng_iter_frames(value v_cap, value v_cb) {
  CAMLparam2(v_cap, v_cb);
  // Make the callback a GC root while we are looping.
  caml_register_global_root(&v_cb);

  std::unique_ptr<pcapng::Capture>* pcap = (std::unique_ptr<pcapng::Capture>*)Data_custom_val(v_cap);
  if (!pcap->get()) caml_failwith("Capture already closed");

  // Iterate over the C++ vector.
  for (auto it = (*pcap)->begin(); it != (*pcap)->end(); ++it) {
    // Wrap the current Frame* into an OCaml value.
    value v_frame = caml_wrap_frame(&(*it));
    // Call the OCaml closure.  Any exception propagates out.
    caml_callback(v_cb, v_frame);
    // No need to free v_frame – its finalizer does nothing.
  }

  caml_remove_global_root(&v_cb);
  CAMLreturn(Val_unit);
}

/* -----------------------------------------------------------------
   Accessors for a single frame
   ----------------------------------------------------------------- */

CAMLprim value caml_pcapng_timestamp(value v_frame) {
  CAMLparam1(v_frame);
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v_frame);
  if (!f) caml_failwith("Frame already invalid");
  CAMLreturn(caml_copy_double(f->ts));
}

CAMLprim value caml_pcapng_captured_len(value v_frame) {
  CAMLparam1(v_frame);
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v_frame);
  if (!f) caml_failwith("Frame already invalid");
  CAMLreturn(Val_int(f->cap_len));
}

CAMLprim value caml_pcapng_original_len(value v_frame) {
  CAMLparam1(v_frame);
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v_frame);
  if (!f) caml_failwith("Frame already invalid");
  CAMLreturn(Val_int(f->orig_len));
}

/* data : frame -> string */
CAMLprim value caml_pcapng_data(value v_frame) {
  CAMLparam1(v_frame);
  CAMLlocal1(v_str);
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v_frame);
  if (!f) caml_failwith("Frame already invalid");
  const std::vector<unsigned char>& d = f->data;
  v_str = caml_alloc_string(d.size());
  memcpy(String_val(v_str), d.data(), d.size());
  CAMLreturn(v_str);
}

/* Helper to extract a MAC address if the frame looks like Ethernet.
   Returns a string of length 6 (binary) or 0 if not enough bytes. */
static value mac_opt(const unsigned char* src, size_t len) {
  if (len < 6) return Val_int(0); // None
  value v = caml_alloc_some(); // allocate Some(_)
  // The payload of Some is at Field(v, 0)
  value mac = caml_alloc_string(6);
  memcpy(String_val(mac), src, 6);
  Store_field(v, 0, mac);
  return v;
}

/* eth_src : frame -> string option */
CAMLprim value caml_pcapng_eth_src(value v_frame) {
  CAMLparam1(v_frame);
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v_frame);
  if (!f) caml_failwith("Frame already invalid");
  const auto& d = f->data;
  // Ethernet src MAC starts at offset 6 (after dst MAC)
  if (d.size() < 12) CAMLreturn(Val_int(0)); // None
  value mac = caml_alloc_string(6);
  memcpy(String_val(mac), d.data() + 6, 6);
  CAMLreturn(caml_alloc_some(mac));
}

/* eth_dst : frame -> string option */
CAMLprim value caml_pcapng_eth_dst(value v_frame) {
  CAMLparam1(v_frame);
  pcapng::Frame* f = *(pcapng::Frame**)Data_custom_val(v_frame);
  if (!f) caml_failwith("Frame already invalid");
  const auto& d = f->data;
  if (d.size() < 6) CAMLreturn(Val_int(0)); // None
  value mac = caml_alloc_string(6);
  memcpy(String_val(mac), d.data(), 6);
  CAMLreturn(caml_alloc_some(mac));
}

} // extern "C"
```

### Explanation of the stub design

| Feature | How it is implemented |
|---------|-----------------------|
| **Opaque handles** (`capture`, `frame`) | Stored as OCaml *custom blocks* that contain a pointer to a C++ object (`std::unique_ptr<Capture>` for the file handle, raw `Frame*` for a frame).  The custom finalisers free the resources automatically. |
| **Opening / closing** | `open_file` creates a new `pcapng::Capture` and wraps it.  `close` resets the `unique_ptr`.  The finaliser does the same, so explicit `close` is optional but convenient. |
| **Iterating with a user closure** | `iter_frames` receives the OCaml closure (`v_cb`).  It registers it as a global root while the C++ loop runs (so the GC cannot move/collect it).  For each frame it creates a temporary OCaml `frame` value and calls `caml_callback(v_cb, v_frame)`.  If the OCaml closure raises, the exception propagates out of `iter_frames`. |
| **Thread safety** | The stub does *not* release the OCaml runtime lock because the iteration runs entirely inside OCaml code (the callback may allocate, raise, etc.).  If you ever need to run a *blocking* C++ operation, wrap the loop in `caml_release_runtime_system()` / `caml_acquire_runtime_system()`. |
| **Accessors** (`timestamp`, `captured_len`, …) | Simple wrappers that dereference the stored `Frame*` and copy the data into OCaml values (`caml_copy_double`, `Val_int`, `caml_alloc_string`). |
| **Optional helpers** (`eth_src`, `eth_dst`) | Demonstrate returning an `'a option` (`Some`/`None`) using the internal macro `caml_alloc_some`.  They inspect the raw byte vector; real code would probably consult the libpcapng API for Ethernet parsing. |

### Build instructions (for completeness)

```bash
# 1. Compile the stub as C++
ocamlopt -c -thread -ccopt "-std=c++17 -I/usr/include/pcapng" pcapng_stubs.cpp

# 2. Build the OCaml library
ocamlopt -c pcapng.mli
ocamlopt -c pcapng.ml          # (empty – just to generate the .cmi)

# 3. Archive the objects
ocamlopt -a -o libpcapng.cmxa pcapng.cmx pcapng_stubs.o -cclib -lpcapng

# 4. Use it from another OCaml program
ocamlopt -thread -o demo.exe pcapng.cmxa demo.ml
```

(Replace `-I/usr/include/pcapng` and `-lpcapng` with the actual include path / library name of the real libpcapng you are binding to.)

